export function getProjectById(id: string): Project | undefined {
  return projects.find((p) => p.id === id);
}

export function slugify(title: string): string {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
}
